// RISC-style: Sum array elements using registers
// C requires: sum = a[0] + a[1] + ... + a[9]

// Assume base address of array 'a' in $t0, sum in $t1
LOAD $t1, $zero // sum = 0
LOAD $t2, $zero // i = 0

LOOP:
 // Check if i < 10
 SLT $t3, $t2, 10 // $t3 = (i < 10) ? 1 : 0
 BEQ $t3, $zero, EXIT // if i >= 10, exit

 // Load a[i] into register
 SLL $t4, $t2, 2 // $t4 = i * 4 (word offset)
 ADD $t5, $t0, $t4 // address = base + offset
 LOAD $t6, ($t5) // load a[i] into $t6

 // Add to sum (register-to-register operation)
 ADD $t1, $t1, $t6 // sum = sum + a[i]

 // Increment i
 ADDI $t2, $t2, 1 // i = i + 1
 J LOOP

EXIT:
 STORE $t1, result // store sum to memory

// Pipeline simulation showing 5 instructions
// Each instruction goes through: IF, ID, EX, MEM, WB

// Cycle 1: Only I1 is in IF
// Cycle 2: I1 in ID, I2 in IF
// Cycle 3: I1 in EX, I2 in ID, I3 in IF
// Cycle 4: I1 in MEM, I2 in EX, I3 in ID, I4 in IF
// Cycle 5: I1 in WB, I2 in MEM, I3 in EX, I4 in ID, I5 in IF
// Cycle 6: I2 in WB, I3 in MEM, I4 in EX, I5 in ID, I6 in IF
// Cycle 7: I3 in WB, I4 in MEM, I5 in EX, I6 in ID
// ... and so on

// After initial pipeline fill (5 cycles), 
// one instruction completes every cycle
// Total for n instructions: 5 + (n-1) = n+4 cycles
// Without pipeline: 5*n cycles

// Original code:
// if (a > b) goto TARGET;
// x = x + 1;

// Without delayed branch:
BEQ $t1, $t2, TARGET // branch if a <= b
// Pipeline stalls until branch resolved
ADD $t3, $t3, 1 // x = x + 1 (executed even if branch taken!)

// With delayed branch (1 delay slot):
BEQ $t1, $t2, TARGET // branch if a <= b
ADD $t3, $t3, 1 // delay slot: always executes before branch
// This instruction executes regardless
// Then PC jumps to TARGET

// Compiler optimization:
// If instruction before branch is useless after branch,
// move a useful instruction into delay slot
// Original:
// y = a + b;
// if (a > b) goto TARGET;
// z = y + 1;

// Optimized:
ADD $t3, $t1, $t2 // y = a + b
BEQ $t1, $t2, TARGET // delayed branch
ADD $t4, $t3, 1 // delay slot: z = y + 1
